import {describe,it,expect} from 'vitest';
import crypto from 'node:crypto';

function hashBucket(key:string,buckets:number):number{
  return crypto.createHash('md5').update(key).digest().readUInt32BE(0)%buckets;
}

describe('hashBucket distribution',()=>{
  it('distributes uniformly across 16 buckets',()=>{
    const N=16000,buckets=16;
    const counts=Array(buckets).fill(0);
    for(let i=0;i<N;i++)counts[hashBucket(`user-${i}`,buckets)]++;
    const expected=N/buckets;
    for(const c of counts){
      expect(c).toBeGreaterThan(expected*0.85);
      expect(c).toBeLessThan(expected*1.15);
    }
  });
});

