export type Action={type:'setField';name:string;value:string}|{type:'reset'}|{type:'submit'};
export interface State{fields:Record<string,string>;submitting:boolean;submitted:boolean}
export const initial:State={fields:{},submitting:false,submitted:false};
export function reducer(state:State,action:Action):State{
  switch(action.type){
    case 'setField':return {...state,fields:{...state.fields,[action.name]:action.value}};
    case 'reset':return initial;
    case 'submit':return {...state,submitting:true};
  }
}

