import {forwardRef,useImperativeHandle,useRef,useState} from 'react';
export interface PlayerHandle{play():void;pause():void;currentTime:number}
export const Player=forwardRef<PlayerHandle,{src:string}>(function Player({src},ref){
  const v=useRef<HTMLVideoElement>(null);
  const [time,setTime]=useState(0);
  useImperativeHandle(ref,()=>({
    play(){v.current?.play().catch(()=>{});},
    pause(){v.current?.pause();},
    get currentTime(){return v.current?.currentTime??0;}
  }),[]);
  return <video ref={v} src={src} onTimeUpdate={(e)=>setTime((e.target as HTMLVideoElement).currentTime)}/>;
});

