import {Buffer} from 'node:buffer';

function encode(b:Buffer):string{return b.toString('base64url');}
function decode(s:string):Buffer{return Buffer.from(s,'base64url');}

describe('base64url round-trip',()=>{
  it('decode(encode(b)) === b',()=>{
    fc.assert(fc.property(fc.uint8Array({maxLength:1000}),(arr)=>{
      const b=Buffer.from(arr);
      return Buffer.compare(decode(encode(b)),b)===0;
    }),{numRuns:1000});
  });
});

export function canPurchase(user:{age:number;hasPayment:boolean;banned:boolean},item:{ageRestricted:boolean;adultOnly:boolean}):boolean{
  if(user.banned)return false;
  if(item.adultOnly&&user.age<18)return false;
  if(item.ageRestricted&&user.age<13)return false;
  return user.hasPayment;
}

