import {useState,useEffect} from 'react';
function useDebounced<T>(v:T,ms:number){const [d,setD]=useState(v);useEffect(()=>{const t=setTimeout(()=>setD(v),ms);return ()=>clearTimeout(t);},[v,ms]);return d;}
export function Search({onSearch}:{onSearch:(q:string)=>void}){
  const [q,setQ]=useState('');
  const dq=useDebounced(q,300);
  useEffect(()=>{if(dq)onSearch(dq);},[dq,onSearch]);
  return <input aria-label="search" value={q} onChange={(e)=>setQ(e.target.value)}/>;
}

